const ideias = Array.isArray($('GET Ideias da Semana').first()?.json) ? $('GET Ideias da Semana').first().json : [];
const staged = Array.isArray($('GET Staged da Semana').first()?.json) ? $('GET Staged da Semana').first().json : [];
const posts  = Array.isArray($('GET Posts da Semana').first()?.json)  ? $('GET Posts da Semana').first().json  : [];

const semanaInicio = new Date(Date.now()-7*86400000).toLocaleDateString('pt-BR');
const semanaFim    = new Date().toLocaleDateString('pt-BR');

const aprovadas  = ideias.filter(i => ['Aprovado','Concluído','Concluido'].includes(i.status));
const rejeitadas = ideias.filter(i => i.status === 'Rejeitado');
const andamento  = ideias.filter(i => i.status === 'Em andamento');

const stAprov = staged.filter(s => s.status === 'Aprovado');
const stRej   = staged.filter(s => s.status === 'Rejeitado');

const totalImp    = posts.reduce((s,p)=>s+(p.impressoes||0),0);
const totalLikes  = posts.reduce((s,p)=>s+(p.likes||0),0);
const totalViews  = posts.reduce((s,p)=>s+(p.views||0),0);
const totalComent = posts.reduce((s,p)=>s+(p.comentarios||0),0);
const totalComp   = posts.reduce((s,p)=>s+(p.compartilhamentos||0),0);

const systemPrompt = `Você é um estrategista de conteúdo B2B especializado no setor de autopeças.
Sua tarefa: analisar uma semana de operação e gerar dois documentos estratégicos.

1. RESUMO_VALIDACAO: Guia para a IA que gerará posts na semana seguinte.
   - O que o usuário aprovou vs rejeitou e por quê
   - Padrões de estilo, tom e tema que funcionam
   - O que evitar especificamente
   - Instruções concretas para melhorar os próximos posts

2. RESUMO_SEMANAL: Relatório executivo.
   - Números da semana (ideias, posts, aprovações, rejeições)
   - Performance dos posts (impressões, likes, views)
   - Tendências e insights acionáveis
   - Recomendações para a próxima semana

Escreva em português brasileiro. Seja específico e direto.
Retorne SOMENTE JSON válido sem markdown.`;

const userPrompt = `PERÍODO: ${semanaInicio} a ${semanaFim}

IDEIAS DA SEMANA (${ideias.length} total):
- Em andamento: ${andamento.length}
- Aprovadas/Concluídas: ${aprovadas.length}
- Rejeitadas: ${rejeitadas.length}

Aprovadas:\n${JSON.stringify(aprovadas.map(i=>({tema:i.assunto_tema,plataforma:i.plataforma,formato:i.formato})))}

Rejeitadas (com motivo):\n${JSON.stringify(rejeitadas.map(i=>({tema:i.assunto_tema,motivo:i.motivo_rejeicao||'não informado'})))}

STAGED LINKEDIN (${staged.length} total):
- Aprovados: ${stAprov.length}
- Rejeitados: ${stRej.length}
Rejeitados:\n${JSON.stringify(stRej.map(s=>({motivo:s.motivo_rejeicao||'não informado',trecho:(s.conteudo_gerado||'').substring(0,100)})))}

POSTS PUBLICADOS (${posts.length}):
Imprões:${totalImp} | Views:${totalViews} | Likes:${totalLikes} | Comentários:${totalComent} | Compart:${totalComp}
Detalhes:\n${JSON.stringify(posts.map(p=>({plataforma:p.plataforma,formato:p.formato,impressoes:p.impressoes,likes:p.likes,views:p.views,trecho:(p.conteudo_post||'').substring(0,80)})))}

Retorne EXATAMENTE:
{
  "padroes_aprovados": "<o que funciona: temas, tons, formatos aprovados>",
  "padroes_rejeitados": "<o que não funciona: temas, tons, motivos das rejeições>",
  "analise_combinada": "<análise integrada com recomendações específicas para a IA na próxima semana>",
  "insights": "<insights de performance e oportunidades>",
  "resumo_semanal": "<relatório executivo completo com números, análise e recomendações>",
  "temas_relevantes": "<temas e assuntos que geraram mais engajamento ou interesse>",
  "sugestoes_conteudo": "<3 a 5 sugestões concretas de posts para a próxima semana>"
}`;

return [{
  json: {
    semanaFim,
    stats: { ideias: ideias.length, aprovadas: aprovadas.length, rejeitadas: rejeitadas.length, posts: posts.length, totalImp, totalLikes, totalViews },
    claudeBody: {
      model: 'claude-sonnet-4-6',
      max_tokens: 4096,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }]
    }
  }
}];

const claudeResp = $input.first().json;
const ctx = $('Preparar Análise Semanal').first().json;

const text = claudeResp.content?.[0]?.text || '';
if (!text) throw new Error('Claude vazio: ' + JSON.stringify(claudeResp.error));

const match = text.match(/\{[\s\S]*\}/);
if (!match) throw new Error('Sem JSON na resposta: ' + text.substring(0,300));

let r;
try { r = JSON.parse(match[0]); }
catch(e) { throw new Error('Parse falhou: ' + e.message); }

const semana = ctx.semanaFim;

return [{
  json: {
    // Payload p/ INSERT resumo_validacao (colunas reais da tabela)
    validacao: {
      semana,
      padroes_aprovados:  r.padroes_aprovados  || '',
      padroes_rejeitados: r.padroes_rejeitados || '',
      analise_combinada:  r.analise_combinada  || '',
      insights:           r.insights           || '',
      conteudo:           r.analise_combinada  || '',  // coluna extra p/ leitura simples no fluxo 1
    },
    // Payload p/ INSERT resumo_semanal (colunas reais da tabela)
    semanal: {
      semana,
      resumo:             r.resumo_semanal       || '',
      temas_relevantes:   r.temas_relevantes     || '',
      sugestoes_conteudo: r.sugestoes_conteudo   || '',
      conteudo:           r.resumo_semanal       || '',  // coluna extra p/ leitura simples
    },
    stats: ctx.stats
  }
}];
